#!/usr/bin/env node
import { publishAppAssets, fatal } from "../dist/publishHarmonyApp.js";
import getopts from "getopts";

function printUsageAndExit(error) {
  if (error) {
    console.error(`Error: ${error}`);
  }
  console.log(`Usage: publish-harmony-app [options] <app-directory>

Prepares a package's built assets to be deployed to Harmony.
https://console.harmony.a2z.com/docs/build-system.html

  Options: 
    --apply-legacy-cleaning  Apply legacy cleaning logic to the assets
`);
  process.exit(1);
}

const options = getopts(process.argv.slice(2), {
  alias: {
    "apply-legacy-cleaning": "c",
  },
  boolean: ["apply-legacy-cleaning"],
  unknown: (option) => {
    printUsageAndExit(`Unknown option: ${option}`);
  },
});

console.info(`
       @@@@@    @@@@@
      @@@@@@   @@@@@@
      @@@@@@   @@@@@
     @@@@@@   @@@@@@
     @@@@@@@@@@@@@@      Harmony App Publisher - 🎵 𝄞 🎸 𝄫 🎷🎶 🎻
    @@@@@@@@@@@@@@       https://console.harmony.a2z.com/docs/build-system.html
    @@@@@    @@@@@
   @@@@@@   @@@@@@
   @@@@@    @@@@@
     @@@     @@@@
      @        @
`);

// The last part of the command line is the appDir
const appDir = options._[0];

await publishAppAssets(appDir, options).catch(fatal);
process.on("uncaughtException", fatal);
process.on("unhandledRejection", (err) => {
  console.log("process failed with unhandled rejection", err);
});
